messages.content:
{
  "intent": "check_and_fix",
  "intent_description": "Packets from 192.168.0.12 to 172.16.0.12 are not replied to because R2 lacks a route to 192.168.0.0/24 (causing no return path) and R3's default forwarding points to its Loopback causing black-holing. Desired outcome: restore symmetric return path so ICMP replies reach 192.168.0.12.",
  "target": null,
  "needs_fix": true,
  "plan": {
    "problem": "R2 has no route to 192.168.0.0/24; R3 default route forwards to Loopback1 causing returned packets to be black-holed.",
    "fix_summary": "Add a route on router2 for 192.168.0.0/24 via R1 (10.0.0.1). Correct router3 default route to forward toward R2 (10.0.0.5) instead of Loopback1.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "prefix=192.168.0.0",
          "mask=255.255.255.0",
          "next-hop=10.0.0.1"
        ]
      },
      {
        "id": 2,
        "device": "router3",
        "action": "update_static_route",
        "target": "0.0.0.0/0",
        "parameters": [
          "prefix=0.0.0.0",
          "mask=0.0.0.0",
          "next-hop=10.0.0.5"
        ]
      }
    ]
